**Version Used**: 4.1.0

**Steps to Reproduce**:

I'm attaching a program that reproduces the issue.  
In summary, I'm writing the syntax tree of a C# source with top-level statements into another syntax tree where these (previous) top-level statements are inside a `Main` method. The rewritten syntax (and even the source rewritten from this syntax) look fine, but it the tree contains this diagnostics:

`error CS1547: Keyword 'void' cannot be used in this context`

Here's the program with the rewriting logic; below it, the output that I get when running it.

```
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;

public class T
{
    public static void Main()
    {
        var source = @"
using System;
Console.Write(1);
";

        var originalTree = CSharpSyntaxTree.ParseText(source);
        Console.WriteLine($"<<<{originalTree}>>>\n" +
                          $"number of diagnostics: {originalTree.GetDiagnostics().Count()}\n");

        Console.WriteLine("rewritting the tree...");
        var rewrittenTree = new EmplaceGlobalStatement().Visit(originalTree.GetRoot()).NormalizeWhitespace().SyntaxTree;
        Console.WriteLine($"<<<{rewrittenTree}>>>\n" +
                          $"number of diagnostics: {rewrittenTree.GetDiagnostics().Count()}\n");

        if (rewrittenTree.GetDiagnostics().Count() == 1)
        {
            Console.WriteLine(rewrittenTree.GetDiagnostics().First() + "\n\n" + 
                              "rewritting the rewritten tree (with a diagnostics) back to source...");
            var rewrittenSource = rewrittenTree.ToString();
            var rewrittenSourceTree = CSharpSyntaxTree.ParseText(rewrittenSource);
            Console.WriteLine($"<<<{rewrittenSourceTree}>>>\n" +
                              $"number of diagnostics: {rewrittenSourceTree.GetDiagnostics().Count()}\n");

        }
    }
}

public class EmplaceGlobalStatement : CSharpSyntaxRewriter
{
    private readonly List<StatementSyntax> __stmtsNodes = new();

    public override SyntaxNode VisitCompilationUnit(CompilationUnitSyntax node)
    {
        var node_P = (CompilationUnitSyntax)base.VisitCompilationUnit(node);

        if (!__stmtsNodes.Any())
            return node_P;

        var methDecl =
            SyntaxFactory.MethodDeclaration(
                    SyntaxFactory.ParseTypeName("void"),
                    "Main")
                .WithModifiers(
                    SyntaxFactory.TokenList(
                        SyntaxFactory.Token(SyntaxKind.PublicKeyword),
                        SyntaxFactory.Token(SyntaxKind.StaticKeyword)))
                .WithBody(
                    SyntaxFactory.Block(__stmtsNodes));

        var tyDecl =
            SyntaxFactory.ClassDeclaration("Program")
                .WithModifiers(
                    SyntaxFactory.TokenList(
                        SyntaxFactory.Token(SyntaxKind.InternalKeyword),
                        SyntaxFactory.Token(SyntaxKind.StaticKeyword)))
                .WithMembers(
                    SyntaxFactory.List<MemberDeclarationSyntax>().Add(methDecl));

        node_P = node_P.AddMembers(tyDecl);

        return node_P;
    }

    public override SyntaxNode VisitGlobalStatement(GlobalStatementSyntax node)
    {
        __stmtsNodes.Add(node.Statement);
        return null;
    }
}
```

