    this.iconData, {
    this.isEmpty = false,
  });
}
class Categorieswidget extends StatefulWidget {
  @override
  _CategorieswidgetState createState() => _CategorieswidgetState();
}

class _CategorieswidgetState extends State<Categorieswidget> {
  PageController pageController;
  double itemExtent = 0;
  int emptySpace = 0;
  ScrollPhysics scrollPhysics;
  var categoryList = <CategoryModel>[];

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    calculateWidgetSize();
    categoryList.clear();
    categoryList.add(CategoryModel(Icons.home));
    categoryList.add(CategoryModel(Icons.mail_outline));
    categoryList.add(CategoryModel(Icons.edit_location));
    categoryList.add(CategoryModel(Icons.label));
    categoryList.add(CategoryModel(Icons.edit));
    categoryList.add(CategoryModel(Icons.cached));
    categoryList.add(CategoryModel(Icons.ac_unit));
    categoryList.add(CategoryModel(Icons.edit));
    categoryList.add(CategoryModel(Icons.cached));
    categoryList.add(CategoryModel(Icons.ac_unit));

    final emptyCategory = List.generate(
      emptySpace,
      (index) => CategoryModel(
        null,
        isEmpty: true,
      ),
    );
    categoryList = [
      ...emptyCategory,
      ...categoryList,
      ...emptyCategory,
    ];
      scrollPhysics = SnappingListScrollPhysics(itemExtent: itemExtent);
  }

  void calculateWidgetSize() {
    final size = MediaQuery.of(context).size;
    final width = size.width;
    double itemWidth = 100;
    var tempsize = width / itemWidth;
    var truckedVal = tempsize.truncate();
    if (tempsize % 2 == 0) {
      truckedVal--;
    }
    itemExtent = width / truckedVal;
    emptySpace = (truckedVal / 2).truncate();
  }
 
  @override
  Widget build(BuildContext context) {
    return Stack(
      children: [
        Container(
          height: 100,
          color: Colors.greenAccent[200],
          child: SnappingListView(
            scrollPhysics: scrollPhysics,
            itemExtent: itemExtent,
            itemCount: categoryList.length,
            itemBuilder: (_, index) => getBox(categoryList[index]),
            controller: pageController,
          ),
        ),
        Align(
          alignment: Alignment.topCenter,
          child: Container(
            height: 75,
            width: 75,
            margin: EdgeInsets.all(10),
            decoration: BoxDecoration(border: Border.all()),
          ),
        )
      ],
    );
  }

  Widget getBox(CategoryModel category) {
    if (category.isEmpty) {
      return Container(
        color: Colors.red, 
      );
    }
    return Container( 
      margin: EdgeInsets.symmetric(horizontal: 10),
      child: Icon(category.iconData),
      color: Colors.blue,
    ); 
  }
}

class SnappingListView extends StatefulWidget {
  final ScrollController controller;
  final ScrollPhysics scrollPhysics;
  final IndexedWidgetBuilder itemBuilder;

  final int itemCount;

  final double itemExtent;
  final ValueChanged<int> onItemChanged;

  SnappingListView({
    @required this.scrollPhysics,
    this.controller,
    @required this.itemBuilder,
    this.itemCount,
    @required this.itemExtent,
    this.onItemChanged,
  });

  @override
  createState() => _SnappingListViewState();
}

class _SnappingListViewState extends State<SnappingListView> {
  int _lastItem = 0;

  bool onNotification(ScrollNotification notif) {
    if (widget.onItemChanged != null &&
        notif is ScrollUpdateNotification &&
        notif.depth == 0) {
      final currItem = notif.metrics.pixels ~/ widget.itemExtent;
      if (currItem != _lastItem) {
        _lastItem = currItem;
        widget.onItemChanged(currItem);
      }
    }
    return false;
  }

  @override
  Widget build(BuildContext context) {
    final listView = ListView.builder(
      scrollDirection: Axis.horizontal,
      controller: widget.controller,
      itemBuilder: widget.itemBuilder,
      itemCount: widget.itemCount,
      itemExtent: widget.itemExtent,
      physics: widget.scrollPhysics,
    );
    return NotificationListener<ScrollNotification>(
      child: listView,
      onNotification: onNotification,
    );
  }
}

class SnappingListScrollPhysics extends ScrollPhysics {
  final double mainAxisStartPadding;
  final double itemExtent;

  const SnappingListScrollPhysics({
    ScrollPhysics parent,
    this.mainAxisStartPadding = 0.0,
    @required this.itemExtent,
  }) : super(parent: parent);

  @override
  SnappingListScrollPhysics applyTo(ScrollPhysics ancestor) {
    return SnappingListScrollPhysics(
      parent: buildParent(ancestor),
      mainAxisStartPadding: mainAxisStartPadding,
      itemExtent: itemExtent,
    );
  }

  double _getItem(ScrollPosition position) {
    return (position.pixels - mainAxisStartPadding) / itemExtent;
  }

  double _getPixels(ScrollPosition position, double item) {
    return min(item * itemExtent, position.maxScrollExtent);
  }

  double _getTargetPixels(
    ScrollPosition position,
    Tolerance tolerance,
    double velocity,
  ) {
    double item = _getItem(position);
    if (velocity < -tolerance.velocity) {
      item -= 0.5;
    } else if (velocity > tolerance.velocity) {
      item += 0.5;
    }
    return _getPixels(position, item.roundToDouble());
  }

  @override
  Simulation createBallisticSimulation(
    ScrollMetrics position,
    double velocity,
  ) {
    // If we're out of range and not headed back in range, defer to the parent
    // ballistics, which should put us back in range at a page boundary.
    if ((velocity <= 0.0 && position.pixels <= position.minScrollExtent) ||
        (velocity >= 0.0 && position.pixels >= position.maxScrollExtent))
      return super.createBallisticSimulation(position, velocity);
    final Tolerance tolerance = this.tolerance;
    final double target = _getTargetPixels(position, tolerance, velocity);
    if (target != position.pixels)
      return ScrollSpringSimulation(
        spring,
        position.pixels,
        target,
        velocity,
        tolerance: tolerance,
      );
    return null;
  }

  @override
  bool get allowImplicitScrolling => false;
}

